import{_ as r,o as e,c as t,ai as s}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"海量数据：分库分表与全局 ID【中级】","description":"","frontmatter":{},"headers":[],"relativePath":"database/sharding.md","filePath":"database/sharding.md"}'),n={name:"database/sharding.md"};function d(i,o,a,g,l,c){return e(),t("div",null,[...o[0]||(o[0]=[s('<h1 id="海量数据-分库分表与全局-id【中级】" tabindex="-1">海量数据：分库分表与全局 ID【中级】 <a class="header-anchor" href="#海量数据-分库分表与全局-id【中级】" aria-label="Permalink to “海量数据：分库分表与全局 ID【中级】”">​</a></h1><hr><h3 id="❓-面试官-什么时候该分表-什么时候该分库" tabindex="-1">❓ 面试官：什么时候该分表？什么时候该分库？ <a class="header-anchor" href="#❓-面试官-什么时候该分表-什么时候该分库" aria-label="Permalink to “❓ 面试官：什么时候该分表？什么时候该分库？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 当<strong>单表数据量过大</strong>（超过千万级）导致 B+ 树变高、查询变慢时，我们需要<strong>分表</strong>；当<strong>单库并发读写太高</strong>（CPU、内存、磁盘 IO 遇到瓶颈）、数据库连接数耗尽时，我们需要<strong>分库</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><p><strong>垂直拆分（按业务列拆分）</strong>：</p><ul><li><strong>垂直分库</strong>：按业务模块，把原本在一个库里的表（如用户表、订单表、商品表）拆分到不同的数据库实例中。这其实就是微服务架构的基础。</li><li><strong>垂直分表</strong>：把一张字段很多的宽表，按字段的使用频率拆分成主表和扩展表。比如 <code>user_base</code>（存高频访问的 id、name）和 <code>user_ext</code>（存低频访问的个人简介、头像等），减少每次查询读取的数据页大小。</li></ul></li><li><p><strong>水平拆分（按行拆分，最核心的技术）</strong>：</p><ul><li><strong>水平分库</strong>：把同一张表的数据（比如 1 亿条订单），按一定规则（如 <code>user_id</code> 的哈希）拆分到不同的数据库服务器上。<strong>能解决单机存储容量和单机并发瓶颈</strong>。</li><li><strong>水平分表</strong>：把同一张表的数据，按规则拆分到同一个数据库的多个表中（如 <code>order_0</code>、<code>order_1</code>... <code>order_31</code>）。<strong>只能解决单表数据量过大导致的 B+ 树查询慢问题，不能解决单机数据库的性能瓶颈</strong>。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 面试时我通常会强调：&quot;分库分表是能不搞就不搞的最后手段&quot;。在决定分库分表前，我一定会先尝试：</p><ol><li>优化 SQL 和索引。</li><li>升级硬件（加内存、换 SSD 甚至 NVMe 磁盘）。</li><li>引入 Redis 缓存挡住读请求。</li><li>做冷热数据分离（把半年前的历史数据归档到另一张表或 HBase 中）。 只有当以上方案都无法解决，且评估未来 3 年单表确实会突破 5000 万甚至过亿时，才会慎重启动分库分表（比如采用 ShardingSphere-JDBC 框架进行水平拆分）。</li></ol><hr><h3 id="❓-面试官-分库分表时-sharding-key-分片键-怎么选-非分片键怎么查询" tabindex="-1">❓ 面试官：分库分表时，Sharding Key（分片键）怎么选？非分片键怎么查询？ <a class="header-anchor" href="#❓-面试官-分库分表时-sharding-key-分片键-怎么选-非分片键怎么查询" aria-label="Permalink to “❓ 面试官：分库分表时，Sharding Key（分片键）怎么选？非分片键怎么查询？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 分片键应该选择<strong>数据分布均匀且查询最频繁</strong>的字段，通常是 <code>user_id</code>。对于非分片键（如 <code>order_id</code>）的查询，通常采用<strong>&quot;建立映射关系表&quot;</strong>或<strong>&quot;基因法（将 user_id 融入 order_id）&quot;</strong>或<strong>&quot;双写 ES&quot;</strong>来解决。</p><p><strong>📝 详细原理解析：</strong><strong>1. 为什么通常选 <code>user_id</code> 作为分片键？</strong> 绝大多数 C 端业务的查询都是围绕用户展开的（如&quot;查询我的订单&quot;）。如果我们按 <code>user_id % 32</code> 分库，同一个用户的所有订单都会落到同一个库里，查询时直接定位到一个库，完全不需要跨库跨表，性能极高。</p><p><strong>2. 遇到&quot;用订单号查订单（非分片键）&quot;怎么办？</strong> 如果只传 <code>order_id</code>，由于不知道对应的 <code>user_id</code>，系统就不知道去哪个库查，只能<strong>全库全表路由广播（极其消耗性能）</strong>。 解决方案：</p><ul><li><strong>方案 A（基因法/ID 融合法，强烈推荐）</strong>：在生成 <code>order_id</code> 时，把 <code>user_id</code> 的后几位（比如最后 4 位，即路由基因）拼接在 <code>order_id</code> 的末尾。这样拿到 <code>order_id</code> 后，直接截取最后 4 位进行 Hash 取模，就能完美路由到对应的库表！</li><li><strong>方案 B（建立映射表）</strong>：建一张单独的路由表 <code>(order_id, user_id)</code>，由于数据量不大，可以不分库或只分少量的库。先查映射表拿到 <code>user_id</code>，再去查真实的订单表。（缺点是多了一次查询）。</li></ul><p><strong>3. 遇到&quot;运营后台要根据时间、金额等多维度查订单&quot;怎么办？</strong> 方案：<strong>双写 Elasticsearch（ES）</strong>。将分库分表后的数据通过 Canal + MQ 实时同步到 ES 中。所有复杂的、多维度的、分页的运营侧查询，全部走 ES，查到 ID 后再回源数据库获取详情。</p><hr><h3 id="❓-面试官-分库分表后-自增主键不能用了-你们是怎么生成全局唯一-id-的" tabindex="-1">❓ 面试官：分库分表后，自增主键不能用了，你们是怎么生成全局唯一 ID 的？ <a class="header-anchor" href="#❓-面试官-分库分表后-自增主键不能用了-你们是怎么生成全局唯一-id-的" aria-label="Permalink to “❓ 面试官：分库分表后，自增主键不能用了，你们是怎么生成全局唯一 ID 的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 分库分表后，各表各自自增会导致 ID 冲突。我们主要使用<strong>雪花算法（Snowflake）</strong>或者<strong>基于 Redis/数据库号段模式（如滴滴的 TinyId、美团的 Leaf）</strong>来生成全局唯一的分布式 ID。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><p><strong>UUID（极不推荐）</strong>：</p><ul><li>优点：本地生成，性能极高，绝对唯一。</li><li>缺点：32 位字符串太长，无序。<strong>插入 B+ 树时会引发严重的页分裂和碎片</strong>，极大影响插入性能，且无法做范围查询。</li></ul></li><li><p><strong>雪花算法 Snowflake（最常用）</strong>：</p><ul><li>原理：生成一个 64 位的 long 型数字。由 1 位符号位 + 41 位时间戳（毫秒级） + 10 位机器 ID（最多 1024 台机器） + 12 位序列号（每台机器每毫秒可生成 4096 个 ID）组成。</li><li>优点：本地生成，不依赖中心化组件，趋势递增（对 B+ 树极度友好），性能极高。</li><li>缺点：<strong>强依赖机器时钟</strong>，如果服务器发生时钟回拨，可能会生成重复 ID。目前开源框架（如百度 UidGenerator）基本都解决了时钟回拨问题。</li></ul></li><li><p><strong>数据库号段模式（Leaf/TinyId）</strong>：</p><ul><li>原理：业务服务每次向数据库申请一批 ID（比如 1000 个，叫一个号段），缓存在本地内存中。发完这 1000 个再去申请下一批。</li><li>优点：生成也是纯内存操作，发号器宕机也不影响短期的 ID 生成，ID 是绝对单调递增的。</li><li>缺点：依赖中心化数据库，如果数据库彻底挂了就无法生成新的号段。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 如果在微服务中使用了雪花算法生成了 <code>Long</code> 类型的全局 ID 返回给前端，一定要注意 <strong>JS 的精度丢失问题</strong>。 Java 的 Long 最大值是 $2^{63}-1$，而 JavaScript 中 Number 类型能安全表示的最大整数是 $2^{53}-1$。雪花算法生成的 ID 往往超出了 JS 的安全范围，传到前端后末尾几位会被直接截断变成 <code>000</code>。 <strong>解决方案</strong>：在 Spring Boot 中配置全局消息转换器（如 Jackson），在序列化时，只要遇到 <code>Long</code> 类型的全局 ID，统统<strong>转成 String 字符串</strong>再返回给前端。</p>',24)])])}const _=r(n,[["render",d]]);export{u as __pageData,_ as default};
